(717, 'auction_winner_23_9faa2b98c8558bcd2f1d7ca43b5108c0', 'default', '[\"bettaword@outlook.co.th\"]', NULL, NULL, 'You won the auction: Mahacheiensis Green', '<p>Hello Betta Word,</p><p><strong>Congratulations.</strong> You have won the auction on Bettavaro.</p><p><strong>Listing:</strong> Mahacheiensis Green<br><strong>Listing ID:</strong> 23<br><strong>Final Price:</strong> USD 37.00</p><p>Please complete payment from the secure payment page before the due time.</p><p>Regards,<br>Bettavaro</p>', 'Hello Betta Word,\nCongratulations. You have won the auction on Bettavaro.\nListing: Mahacheiensis Green\nListing ID: 23\nFinal Price: USD 37.00\nPlease complete payment from the secure payment page before the due time.\nRegards,\nBettavaro', NULL, '{\"type\":\"auction_winner\",\"listing_id\":23}', 'sent', 0, 3, NULL, NULL, '2026-05-14 15:00:08', NULL, NULL, '2026-05-14 15:00:10', '2026-05-14 15:00:10', '2026-05-14 15:00:08', '2026-05-14 15:00:10'),
